import type {SidebarsConfig} from '@docusaurus/plugin-content-docs';

// This runs in Node.js - Don't use client-side code here (browser APIs, JSX...)

// Two sidebars off the same docs instance, to keep hand-authored guides visibly
// separate from the codegen schema reference:
//   - guidesSidebar: the hand-written docs at the docs/ root (explicit list, so
//     the generated content/ subtree never leaks in).
//   - apiSidebar: the live-rendered schema reference under content/, autogenerated.
const sidebars: SidebarsConfig = {
  guidesSidebar: [
    'README',
    {
      type: 'category',
      label: 'Guides',
      items: [{type: 'autogenerated', dirName: '00-guides'}],
    },
    {
      type: 'category',
      label: 'Project',
      items: [{type: 'autogenerated', dirName: '01-project'}],
    },
  ],

  apiSidebar: [{type: 'autogenerated', dirName: 'content'}],
};

export default sidebars;
